class Solution:
    def deleteNode(self, node):
        vals = []
        cur = node.next
        while cur:
            vals.append(cur.val)
            cur = cur.next
        cur = node
        for i, v in enumerate(vals):
            cur.val = v
            if i == len(vals) - 1:
                cur.next = None
            else:
                cur = cur.next

